import React, { Component } from 'react';
import AllManga from './Components/MainContainer/AllManga.js';
class Navbar extends Component {
    render() {
        return (
        <Router>
            <nav>
                <img src="/logo.png" alt="Logo" className="logo"/>
                <div className="menu">
                    <a href="/Home">Home</a>
                    <Link to="/AllManga">About</Link>
                    <a href="/LatestUpdates">Latest Updates</a>
                    <a href="/AdvancedSearch">Advanced Search<i className="fas  fa-sort-down"></i></a>
                </div>
                <div className="search-bar">
                    <input type="text" placeholder="Search..."/>
                    <button><i className="fas fa-search"></i></button>
                </div>
                <Route path="/AllManga" component={AllManga}/> 
            </nav>
        </Router>
        );
    }
}

export default Navbar;
